INSERT INTO person (id, first_name, last_name, middle_names, notes, sex, birth_id, death_id, burial_id, father_id, mother_id) VALUES (85, 'Fredrik', 'Hegardt', 'Bernhard', 'Studentexamen i Göteborg 1874. Examen till rättegångsverken 1879. Eo Notarie i Göta hovrätt samma år. Kansliexamen 1890. V häradshövding 1882. Kammarförvant vid stadskamrerarkontoret i Göteborg 1885 - 1895. Sekreterare för styrelsen för Göteborgs hamn 1892. Sekreterare hos stadsfullmäktige i samma stad 1895 - 1926. Øverförmyndare i Göteborg. RVO 1903, RNO 1914 och KVO 1923.
